<?php
 namespace WPAICG\Core; use WPAICG\Chat\Core\AIPKit_Content_Aware; if (!defined('ABSPATH')) { exit; } class AIPKit_Instruction_Manager { public static function build_instructions(array $context = []): string { $base_instructions = isset($context['base_instructions']) ? trim($context['base_instructions']) : ''; $bot_settings = $context['bot_settings'] ?? []; $post_id = $context['post_id'] ?? 0; $vector_search_results = $context['vector_search_results'] ?? null; $content_aware_enabled = isset($bot_settings['content_aware_enabled']) && $bot_settings['content_aware_enabled'] === '1'; $prepended_context = ''; if ($content_aware_enabled && $post_id > 0) { if (!class_exists(AIPKit_Content_Aware::class)) { $content_aware_path = WPAICG_PLUGIN_DIR . 'classes/chat/core/class-aipkit_content_aware.php'; if (file_exists($content_aware_path)) { require_once $content_aware_path; } } if (class_exists(AIPKit_Content_Aware::class)) { $content_snippet = AIPKit_Content_Aware::get_content_snippet($post_id); if ($content_snippet !== null) { $prepended_context .= $content_snippet . "\n\n"; } } } if (!empty($vector_search_results) && is_string($vector_search_results)) { $prepended_context .= "## Relevant information from knowledge base:\n" . trim($vector_search_results) . "\n##\n\n"; } $processed_base = self::process_base_instructions($base_instructions); $final_instructions = trim($prepended_context . $processed_base); $final_instructions = apply_filters('aipkit_final_system_instruction', $final_instructions, $context); return trim($final_instructions); } private static function process_base_instructions(string $instructions_raw): string { if (empty($instructions_raw)) { $instructions_raw = __("You are a helpful AI Assistant.", 'gpt3-ai-content-generator'); } if (strpos($instructions_raw, '[date]') !== false) { $current_date = wp_date(get_option('date_format', 'F j, Y')); $instructions_raw = str_replace('[date]', $current_date, $instructions_raw); } if (strpos($instructions_raw, '[username]') !== false) { $username = ''; if (function_exists('wp_get_current_user')) { $user = wp_get_current_user(); if ($user && $user->exists()) { $username = $user->user_login ?: ''; } } $username = apply_filters('aipkit_instruction_username', $username); $instructions_raw = str_replace('[username]', $username, $instructions_raw); } return $instructions_raw; } } 